from contextlib import contextmanager
import duckdb

@contextmanager
def get_db():
    con = duckdb.connect('analytics.duckdb', read_only=True)
    try:
        yield con
    finally:
        con.close()

# FastAPI route
@app.get("/stats")
def stats():
    with get_db() as con:
        return con.execute("SELECT count(*) FROM events").fetchone()[0]
